import { CommonModule } from "@angular/common";
import { Component, OnInit, inject } from "@angular/core";
import { FormsModule } from "@angular/forms";
import { ActivatedRoute, Router, RouterLink } from "@angular/router";
import { LecturerService } from "../../services/lecturer.service";

@Component({
  selector: "app-lecturer-monitoring",
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: "./lecturer-monitoring.component.html",
  styleUrl: "./lecturer-monitoring.component.css"
})
export class LecturerMonitoringComponent implements OnInit {
  private readonly lecturerService = inject(LecturerService);
  private readonly route = inject(ActivatedRoute);
  private readonly router = inject(Router);

  quizzes: any[] = [];
  results: any[] = [];
  resultDetail: any = null;
  showResultDetailModal = false;
  adjustingAnswerId: number | null = null;
  resultQuizId: number | null = null;
  studentFilter = "";
  adjustingDraft: Record<number, string> = {};
  adjustReasonDraft: Record<number, string> = {};
  loading = true;
  statusMessage = "";
  errorMessage = "";
  scopedCourseId: number | null = null;
  scopedCourseTitle = "";

  ngOnInit(): void {
    this.route.queryParamMap.subscribe((params) => {
      const rawCourseId = params.get("courseId");
      const parsedCourseId = rawCourseId ? Number(rawCourseId) : NaN;
      const rawQuizId = params.get("quizId");
      const parsedQuizId = rawQuizId ? Number(rawQuizId) : NaN;
      this.scopedCourseId = Number.isFinite(parsedCourseId) ? parsedCourseId : null;
      this.scopedCourseTitle = (params.get("courseTitle") ?? "").trim();
      this.resultQuizId = Number.isFinite(parsedQuizId) ? parsedQuizId : null;
      this.studentFilter = "";
      this.loadQuizzes();
      this.loadResults();
    });
  }

  loadQuizzes(): void {
    this.lecturerService.quizzes(this.scopedCourseId ?? undefined).subscribe({
      next: (data) => this.quizzes = data,
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to load quizzes"
    });
  }

  loadResults(): void {
    this.loading = true;
    this.lecturerService.results(this.resultQuizId ?? undefined, this.scopedCourseId ?? undefined).subscribe({
      next: (data) => {
        this.results = data;
        this.loading = false;
      },
      error: (error) => {
        this.errorMessage = error?.error?.message ?? "Failed to load results";
        this.loading = false;
      }
    });
  }

  onResultQuizFilter(raw: string): void {
    this.resultQuizId = raw ? Number(raw) : null;
    this.loadResults();
  }

  onStudentFilterChange(raw: string): void {
    this.studentFilter = raw?.trim() ?? "";
  }

  clearCourseScope(): void {
    this.router.navigate(["/lecturer/monitoring"]);
  }

  availableStudents(): string[] {
    const unique = new Set(
      this.results
        .map((item) => String(item.studentName ?? "").trim())
        .filter((name) => !!name)
    );
    return Array.from(unique).sort((a, b) => a.localeCompare(b));
  }

  filteredResults(): any[] {
    const studentKey = this.studentFilter.trim().toLowerCase();
    if (!studentKey) {
      return this.results;
    }
    return this.results.filter((item) =>
      String(item.studentName ?? "").toLowerCase().includes(studentKey)
    );
  }

  openResultDetail(attemptId: number): void {
    this.clearMessages();
    this.lecturerService.resultDetail(attemptId).subscribe({
      next: (data) => {
        this.resultDetail = data;
        this.adjustingDraft = {};
        this.adjustReasonDraft = {};
        this.showResultDetailModal = true;
      },
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to load attempt detail"
    });
  }

  closeResultDetail(): void {
    this.showResultDetailModal = false;
    this.resultDetail = null;
    this.adjustingAnswerId = null;
    this.adjustingDraft = {};
    this.adjustReasonDraft = {};
  }

  getAdjustScore(answer: any): string {
    const answerId = Number(answer.answerId);
    if (!(answerId in this.adjustingDraft)) {
      this.adjustingDraft[answerId] = String(answer.awardedPoints ?? 0);
    }
    return this.adjustingDraft[answerId];
  }

  getAdjustReason(answer: any): string {
    const answerId = Number(answer.answerId);
    if (!(answerId in this.adjustReasonDraft)) {
      this.adjustReasonDraft[answerId] = "";
    }
    return this.adjustReasonDraft[answerId];
  }

  setAdjustScore(answerId: number, value: string): void {
    this.adjustingDraft[answerId] = value;
  }

  setAdjustReason(answerId: number, value: string): void {
    this.adjustReasonDraft[answerId] = value;
  }

  adjustAnswerScore(answer: any): void {
    this.clearMessages();
    const answerId = Number(answer.answerId);
    const current = Number(answer.awardedPoints ?? 0);
    const maxPoints = Number(answer.maxPoints ?? 0);
    const rawScore = this.adjustingDraft[answerId] ?? String(current);
    const awardedPoints = Number(rawScore);
    if (Number.isNaN(awardedPoints)) {
      this.errorMessage = "Invalid score value.";
      return;
    }
    const reason = (this.adjustReasonDraft[answerId] ?? "").trim();

    this.adjustingAnswerId = answerId;
    this.lecturerService.adjustAnswerScore(answerId, { awardedPoints, reason }).subscribe({
      next: () => {
        this.statusMessage = "Score adjusted and recalculated.";
        const attemptId = this.resultDetail?.attempt?.attemptId;
        if (attemptId) {
          this.openResultDetail(attemptId);
        }
        this.loadResults();
        this.adjustingAnswerId = null;
      },
      error: (error) => {
        this.errorMessage = error?.error?.message ?? "Failed to adjust score";
        this.adjustingAnswerId = null;
      }
    });
  }

  formatAnswer(value: unknown): string {
    if (value === null || value === undefined) {
      return "-";
    }
    if (typeof value === "string") {
      const trimmed = value.trim();
      return trimmed || "-";
    }
    if (Array.isArray(value)) {
      return value.map((item) => this.formatAnswer(item)).join(", ");
    }
    if (typeof value === "object") {
      return JSON.stringify(value);
    }
    return String(value);
  }

  private clearMessages(): void {
    this.statusMessage = "";
    this.errorMessage = "";
  }
}
<div class="container monitoring-page">
  <header class="panel monitoring-head">
    <div>
      <h1>Student Result Monitoring</h1>
      <p class="muted">Review attempts, scores, and submitted answers in one dedicated page.</p>
      @if (scopedCourseId) {
        <p class="scope-note">
          Showing course only:
          <strong>{{ scopedCourseTitle || ('Course ID ' + scopedCourseId) }}</strong>
        </p>
      }
    </div>
    <div class="head-actions">
      @if (scopedCourseId) {
        <button class="btn btn-outline" type="button" (click)="clearCourseScope()">Show All Courses</button>
      }
      <a class="btn btn-outline" routerLink="/lecturer/manage">Back to Management</a>
    </div>
  </header>

  @if (statusMessage) {
    <p class="ok">{{ statusMessage }}</p>
  }
  @if (errorMessage) {
    <p class="error">{{ errorMessage }}</p>
  }

  <section class="panel monitoring-table">
    <div class="result-head">
      <h2>Attempts</h2>
      <div class="result-filters">
        <select [ngModel]="resultQuizId ?? ''" (ngModelChange)="onResultQuizFilter($event)" name="resultQuizFilter">
          <option value="">All Quiz</option>
          @for (quiz of quizzes; track quiz.quizId) {
            <option [value]="quiz.quizId">{{ quiz.title }}</option>
          }
        </select>
        <select [ngModel]="studentFilter" (ngModelChange)="onStudentFilterChange($event)" name="resultStudentFilter">
          <option value="">All Students</option>
          @for (studentName of availableStudents(); track studentName) {
            <option [value]="studentName">{{ studentName }}</option>
          }
        </select>
      </div>
    </div>

    @if (loading) {
      <p class="muted">Loading results...</p>
    } @else if (filteredResults().length === 0) {
      <p class="muted">No attempt records yet.</p>
    } @else {
      <div class="table-wrap">
        <table>
          <thead>
            <tr>
              <th>Student</th>
              <th>Quiz</th>
              <th>Attempt</th>
              <th>Score</th>
              <th>Status</th>
              <th>Time Taken</th>
              <th>Date</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            @for (item of filteredResults(); track item.attemptId) {
              <tr>
                <td>{{ item.studentName }}</td>
                <td>{{ item.quizTitle }}</td>
                <td>#{{ item.attemptNumber }}</td>
                <td>{{ item.score }}%</td>
                <td>
                  <span class="badge" [class.fail]="!item.passed">
                    {{ item.passed ? "PASS" : "FAIL" }}
                  </span>
                </td>
                <td>{{ item.durationSeconds || 0 }}s</td>
                <td>{{ item.submittedAt | date: "medium" }}</td>
                <td>
                  <button class="btn btn-outline" type="button" (click)="openResultDetail(item.attemptId)">
                    View Answers
                  </button>
                </td>
              </tr>
            }
          </tbody>
        </table>
      </div>
    }
  </section>

  @if (showResultDetailModal && resultDetail) {
    <div class="modal-backdrop" (click)="closeResultDetail()">
      <section class="modal-shell result-detail-modal" (click)="$event.stopPropagation()">
        <header class="modal-head">
          <h2>Attempt Detail - {{ resultDetail.attempt.studentName }}</h2>
          <button type="button" class="close-btn" (click)="closeResultDetail()">&#10005;</button>
        </header>
        <div class="modal-body">
          <p>
            <strong>{{ resultDetail.attempt.quizTitle }}</strong> |
            Score: {{ resultDetail.attempt.score }}% |
            {{ resultDetail.attempt.passed ? "PASS" : "FAIL" }}
          </p>
          <p class="muted">
            Attempt #{{ resultDetail.attempt.attemptNumber }} |
            Submitted: {{ resultDetail.attempt.submittedAt | date: "medium" }} |
            Time taken: {{ resultDetail.attempt.durationSeconds || 0 }}s
          </p>
          <table>
            <thead>
              <tr>
                <th>Question</th>
                <th>Type</th>
                <th>Student Answer</th>
                <th>Correct Answer</th>
                <th>Auto Result</th>
                <th>Explanation</th>
                <th>Points</th>
                <th>Adjust</th>
              </tr>
            </thead>
            <tbody>
              @for (answer of resultDetail.answers; track answer.answerId) {
                <tr>
                  <td>{{ answer.prompt }}</td>
                  <td>{{ answer.questionType }}</td>
                  <td>{{ formatAnswer(answer.studentAnswer) }}</td>
                  <td>{{ formatAnswer(answer.correctAnswer) }}</td>
                  <td>
                    <span class="badge" [class.fail]="!answer.correct">
                      {{ answer.correct ? "Correct" : "Incorrect" }}
                    </span>
                  </td>
                  <td>{{ answer.explanation || "-" }}</td>
                  <td>{{ answer.awardedPoints }} / {{ answer.maxPoints }}</td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      [max]="answer.maxPoints"
                      [ngModel]="getAdjustScore(answer)"
                      (ngModelChange)="setAdjustScore(answer.answerId, $event)"
                      [name]="'adjust-score-' + answer.answerId">
                    <input
                      type="text"
                      [ngModel]="getAdjustReason(answer)"
                      (ngModelChange)="setAdjustReason(answer.answerId, $event)"
                      [name]="'adjust-reason-' + answer.answerId"
                      placeholder="Reason (optional)">
                    <button
                      class="btn btn-outline"
                      type="button"
                      [disabled]="adjustingAnswerId === answer.answerId"
                      (click)="adjustAnswerScore(answer)">
                      {{ adjustingAnswerId === answer.answerId ? "Saving..." : "Adjust" }}
                    </button>
                  </td>
                </tr>
              }
            </tbody>
          </table>
        </div>
      </section>
    </div>
  }
</div>
